#!/bin/bash
# SubagentStop hook: Auto-promotes hypotheses in shared-learnings.
# Generated by buddyx-forge.

INPUT=$(cat)
if ! command -v jq &>/dev/null; then
  exit 0
fi
AGENT_TYPE=$(echo "$INPUT" | jq -r '.agent_type // empty' 2>/dev/null)
AGENT_TYPE=$(echo "$AGENT_TYPE" | tr -cd 'a-zA-Z0-9-')
LAST_MESSAGE=$(echo "$INPUT" | jq -r '.last_assistant_message // empty' 2>/dev/null)
PROJECT_DIR="$(git rev-parse --show-toplevel 2>/dev/null || pwd)"

if ! echo "$AGENT_TYPE" | grep -q "^myapp-"; then
  exit 0
fi

if [ -z "$LAST_MESSAGE" ] || [ "$LAST_MESSAGE" = "null" ]; then exit 0; fi

SHARED_FILE="${PROJECT_DIR}/.claude/agent-memory/shared-learnings.md"
[ -f "$SHARED_FILE" ] || exit 0

# Look for [CONFIRM: ...] tags in agent output
CONFIRMATIONS=$(echo "$LAST_MESSAGE" | grep -oE '\[CONFIRM:\s*[^]]+\]' | sed 's/\[CONFIRM:\s*//' | sed 's/\]//')

if [ -z "$CONFIRMATIONS" ]; then
  exit 0
fi

(
  flock -x 9
  echo "$CONFIRMATIONS" | while IFS= read -r pattern; do
    [ -z "$pattern" ] && continue

    # Find matching hypothesis in shared-learnings
    ESCAPED_PATTERN=$(echo "$pattern" | head -c 40 | sed 's/[][\\.*^$]/\\&/g')
    MATCH_LINE=$(grep -n "\[NEW [0-2]/3\].*${ESCAPED_PATTERN}" "$SHARED_FILE" | head -1)
    if [ -n "$MATCH_LINE" ]; then
      LINE_NUM=$(echo "$MATCH_LINE" | cut -d: -f1)
      CURRENT=$(sed -n "${LINE_NUM}p" "$SHARED_FILE")

      # Increment counter
      if echo "$CURRENT" | grep -q '\[NEW 0/3\]'; then
        sed -i "${LINE_NUM}s/\[NEW 0\/3\]/[NEW 1\/3]/" "$SHARED_FILE"
      elif echo "$CURRENT" | grep -q '\[NEW 1/3\]'; then
        sed -i "${LINE_NUM}s/\[NEW 1\/3\]/[NEW 2\/3]/" "$SHARED_FILE"
      elif echo "$CURRENT" | grep -q '\[NEW 2/3\]'; then
        sed -i "${LINE_NUM}s/\[NEW 2\/3\]/[CONFIRMED]/" "$SHARED_FILE"
      fi
    fi
  done
) 9>"${SHARED_FILE}.lock"

exit 0
